<?php function ensureBlogTables(PDO $conn): void { $conn->exec( "CREATE TABLE IF NOT EXISTS blog_categories ( id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(120) NOT NULL, slug VARCHAR(120) NOT NULL UNIQUE, description TEXT NULL, post_count INT NOT NULL DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4" ); $conn->exec( "CREATE TABLE IF NOT EXISTS blog_posts ( id INT AUTO_INCREMENT PRIMARY KEY, title VARCHAR(255) NOT NULL, slug VARCHAR(255) NOT NULL UNIQUE, excerpt TEXT NOT NULL, content MEDIUMTEXT NOT NULL, category VARCHAR(120) NOT NULL, author_name VARCHAR(120) NOT NULL, author_initials VARCHAR(10) NULL, author_title VARCHAR(120) NULL, featured_image VARCHAR(255) NULL, is_featured TINYINT(1) NOT NULL DEFAULT 0, read_time INT NOT NULL DEFAULT 5, meta_description VARCHAR(255) NULL, meta_keywords VARCHAR(255) NULL, publish_date DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP, status ENUM('draft','published','archived') NOT NULL DEFAULT 'published', views INT NOT NULL DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX idx_status (status), INDEX idx_category (category), INDEX idx_publish_date (publish_date) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4" ); } function ensureNewsletterTables(PDO $conn): void { $conn->exec( "CREATE TABLE IF NOT EXISTS newsletter_subscribers ( id INT AUTO_INCREMENT PRIMARY KEY, email VARCHAR(190) NOT NULL UNIQUE, status ENUM('active','unsubscribed') NOT NULL DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4" ); $columnExists = (int)$conn->query( "SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA = DATABASE AND TABLE_NAME = 'blog_posts' AND COLUMN_NAME = 'newsletter_sent'" )->fetchColumn(); if ($columnExists === 0) { $conn->exec( "ALTER TABLE blog_posts ADD COLUMN newsletter_sent TINYINT(1) NOT NULL DEFAULT 0, ADD INDEX idx_newsletter_sent (newsletter_sent)" ); } } function updateBlogCategoryCounts(PDO $conn): void { $conn->exec( "UPDATE blog_categories c SET post_count = ( SELECT COUNT(*) FROM blog_posts p WHERE p.category = c.slug AND p.status = 'published' )" ); } function seedBlogData(PDO $conn): void { $categories = [ [ 'name' => 'Security Tips', 'slug' => 'security-tips', 'description' => 'Practical security tips for homes and businesses.' ], [ 'name' => 'Industry News', 'slug' => 'industry-news', 'description' => 'Updates and insights from the Australian security industry.' ], [ 'name' => 'Risk Management', 'slug' => 'risk-management', 'description' => 'Guidance for assessing and reducing security risks.' ], [ 'name' => 'Technology', 'slug' => 'technology', 'description' => 'Security technology trends and best practices.' ], [ 'name' => 'Emergency Response', 'slug' => 'emergency-response', 'description' => 'Incident response planning and rapid action guidance.' ], [ 'name' => 'Compliance', 'slug' => 'compliance', 'description' => 'Regulations, standards, and compliance updates.' ], [ 'name' => 'CCTV & Monitoring', 'slug' => 'cctv-monitoring', 'description' => 'Video surveillance and monitoring best practices.' ], [ 'name' => 'Cybersecurity', 'slug' => 'cybersecurity', 'description' => 'Protecting digital assets and security systems.' ], [ 'name' => 'Event Security', 'slug' => 'event-security', 'description' => 'Crowd management and event safety insights.' ], [ 'name' => 'Corporate Security', 'slug' => 'corporate-security', 'description' => 'Security strategy for corporate environments.' ], [ 'name' => 'Residential Security', 'slug' => 'residential-security', 'description' => 'Home security tips and protection strategies.' ], [ 'name' => 'Training & Awareness', 'slug' => 'training-awareness', 'description' => 'Staff training, drills, and security awareness.' ], [ 'name' => 'Static Guarding', 'slug' => 'static-guarding', 'description' => 'On-site guarding services for consistent protection.' ], [ 'name' => 'Mobile Patrols', 'slug' => 'mobile-patrols', 'description' => 'Mobile patrol coverage for multiple locations.' ], [ 'name' => 'Cash In Transit', 'slug' => 'cash-in-transit', 'description' => 'Secure transport and handling of cash and valuables.' ], [ 'name' => 'Alarm Responses', 'slug' => 'alarm-responses', 'description' => 'Rapid alarm response and incident management.' ], [ 'name' => 'Construction Site Security', 'slug' => 'construction-site-security', 'description' => 'Protection for construction projects and equipment.' ], [ 'name' => 'Commercial Site Security', 'slug' => 'commercial-site-security', 'description' => 'Security solutions for commercial properties.' ], [ 'name' => 'Manufacturing & Warehousing Security', 'slug' => 'manufacturing-warehousing-security', 'description' => 'Security for manufacturing and warehousing facilities.' ] ]; $conn->beginTransaction; try { $categoryStmt = $conn->prepare( "INSERT INTO blog_categories (name, slug, description, post_count) VALUES (:name,:slug,:description, 0) ON DUPLICATE KEY UPDATE name = VALUES(name), description = VALUES(description)" ); foreach ($categories as $category) { $categoryStmt->execute([ ':name' => $category['name'], ':slug' => $category['slug'], ':description' => $category['description'] ]); } $existing = (int)$conn->query("SELECT COUNT(*) FROM blog_posts")->fetchColumn(); if ($existing > 0) { updateBlogCategoryCounts($conn); $conn->commit; return; } $posts = [ [ 'title' => '5 Ways to Strengthen Site Access Control', 'slug' => 'strengthen-site-access-control', 'excerpt' => 'Improve visitor management and reduce unauthorized access with these proven access control strategies.', 'content' => 'Effective access control reduces risk and improves compliance. Start with a clear visitor policy, introduce ID verification for contractors, and ensure entry points are monitored at all times. Combine access control procedures with regular audits and update your credentials policy to prevent misuse.', 'category' => 'security-tips', 'author_name' => 'Jordan Wells', 'author_initials' => 'JW', 'author_title' => 'Security Operations Manager', 'featured_image' => '/images/access-control-and-screening.jpg', 'is_featured' => 1, 'read_time' => 6, 'meta_description' => 'Practical access control tips for safer facilities.', 'meta_keywords' => 'access control, site security, visitor management' ], [ 'title' => 'Alarm Response: What Happens After the Alert', 'slug' => 'alarm-response-after-alert', 'excerpt' => 'Understand the response workflow that keeps sites secure when an alarm is triggered.', 'content' => 'Once an alarm is triggered, our monitoring team verifies the signal, notifies keyholders, and dispatches the closest response unit. A clear escalation plan ensures rapid action and accurate reporting for every incident.', 'category' => 'risk-management', 'author_name' => 'Ava Patel', 'author_initials' => 'AP', 'author_title' => 'Risk & Compliance Lead', 'featured_image' => '/images/alarm-response-security-services.jpg', 'is_featured' => 0, 'read_time' => 5, 'meta_description' => 'How professional alarm response keeps properties protected.', 'meta_keywords' => 'alarm response, monitoring, security response' ], [ 'title' => 'Mobile Patrols for Multi-Site Coverage', 'slug' => 'mobile-patrols-multi-site-coverage', 'excerpt' => 'Mobile patrols deliver a visible deterrent and rapid response for multiple locations.', 'content' => 'Mobile patrols provide cost-effective coverage across multiple sites. With randomized schedules, GPS tracking, and documented inspections, they reduce vulnerabilities and improve incident response times.', 'category' => 'security-tips', 'author_name' => 'Lucas Nguyen', 'author_initials' => 'LN', 'author_title' => 'Field Operations Coordinator', 'featured_image' => '/images/mobile-patrols-security-security.jpg', 'is_featured' => 0, 'read_time' => 4, 'meta_description' => 'Why mobile patrols are ideal for multi-site security.', 'meta_keywords' => 'mobile patrols, multi-site security, patrol services' ], [ 'title' => 'Warehouse Security Trends in 2026', 'slug' => 'warehouse-security-trends-2026', 'excerpt' => 'Key trends shaping warehouse and distribution centre security this year.', 'content' => 'Warehousing security is evolving with stronger perimeter controls, proactive risk assessments, and integrated reporting. Facilities are prioritizing access control, lighting upgrades, and regular patrols to reduce shrinkage and improve compliance.', 'category' => 'industry-news', 'author_name' => 'Sophia Clarke', 'author_initials' => 'SC', 'author_title' => 'Industry Analyst', 'featured_image' => '/images/industrial-security-services.jpg', 'is_featured' => 0, 'read_time' => 7, 'meta_description' => 'Warehouse security trends and best practices for 2026.', 'meta_keywords' => 'warehouse security, distribution centres, security trends' ], [ 'title' => 'Why Security Technology Audits Matter', 'slug' => 'security-technology-audits', 'excerpt' => 'Audits help validate your security systems and keep technology aligned with risk.', 'content' => 'Regular audits identify gaps in camera coverage, alarm response workflows, and access control configurations. A structured audit plan ensures security technology continues to support operational needs and compliance requirements.', 'category' => 'technology', 'author_name' => 'Ethan Rivers', 'author_initials' => 'ER', 'author_title' => 'Security Technology Specialist', 'featured_image' => '/images/corporate-security-services-australia.jpg', 'is_featured' => 0, 'read_time' => 5, 'meta_description' => 'Security technology audits keep your systems effective.', 'meta_keywords' => 'security technology, audits, CCTV' ] ]; $postStmt = $conn->prepare( "INSERT INTO blog_posts (title, slug, excerpt, content, category, author_name, author_initials, author_title, featured_image, is_featured, read_time, meta_description, meta_keywords, publish_date, status) VALUES (:title,:slug,:excerpt,:content,:category,:author_name,:author_initials,:author_title,:featured_image,:is_featured,:read_time,:meta_description,:meta_keywords,:publish_date,:status)" ); foreach ($posts as $post) { $postStmt->execute([ ':title' => $post['title'], ':slug' => $post['slug'], ':excerpt' => $post['excerpt'], ':content' => $post['content'], ':category' => $post['category'], ':author_name' => $post['author_name'], ':author_initials' => $post['author_initials'], ':author_title' => $post['author_title'], ':featured_image' => $post['featured_image'], ':is_featured' => (int)$post['is_featured'], ':read_time' => (int)$post['read_time'], ':meta_description' => $post['meta_description'], ':meta_keywords' => $post['meta_keywords'], ':publish_date' => date('Y-m-d H:i:s'), ':status' => 'published' ]); } updateBlogCategoryCounts($conn); $conn->commit; } catch (Throwable $e) { $conn->rollBack; throw $e; } } 

